+    if (builtin.os.tag == .wasi) {
+        return qjs.JS_NewInt32(ctx, 0);
+    }
+
+    if (argc < 2) {
+        return qjs.JS_NewInt32(ctx, -1);
+    }
+
+    var socket_id: i32 = 0;
+    _ = qjs.JS_ToInt32(ctx, &socket_id, argv[0]);
